def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    constants = np.array([3.14, 2.718, 1.618, 0.577, 1.414])
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 42 * np.exp(-cap / 5) + 60 + np.log1p(cap) * 20 + np.sin(usage * np.pi) * 35
        fluctuation = 0.0
        if usage > 5:
            base_priority += 7000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.sqrt(cap) + 50 * np.cos(cap * 2.3)
            else:
                base_priority -= 60 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 1.2) * 18 / (i + 1)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2000 * delta ** 2 + 300 * np.cos(delta * np.pi)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * j ** 1.5) * 20 / j
            if int(cap * 4) % 5 == 1:
                base_priority += 45 * np.tan(cap / 10)
        elif 3 < usage <= 4:
            base_priority += 1600 * (usage - 3)**2.5
            for k in range(1, 14):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 8 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 15 / (k + 3)
                    if k == 11 and usage > 3.7:
                        fluctuation += 18
            if cap % 3.3 < 0.7:
                base_priority += 40 * np.sin(cap * 2.1)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 20 / m
                    if m % 6 == 2:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 14 / (m + 1)
                    if m == 15 and usage > 2.5:
                        fluctuation += 25
            if cap % 2.7 < 0.4:
                base_priority += 50 * np.cos(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 700 * (usage - 1) ** 4 + 100 * np.sin(usage * 5)
            for n in range(1, 20):
                pwr = usage ** n
                if pwr < 0.55:
                    fluctuation += pwr * 22 / n
                    if n % 5 == 3:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 16 / (n + 4)
                    if n == 17 and usage > 1.85:
                        fluctuation += 30
            if cap % 1.8 < 0.25:
                base_priority += 32 * np.cos(cap * 3)
        elif 0.6 < usage <= 1:
            base_priority += 160 * (1 - usage)**1.5 + 45 * np.tanh(cap)
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / o
                if usage < 0.09 * o:
                    fluctuation -= 9 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 18) * 40
            else:
                base_priority += (cap % 7) * 25
        else:
            base_priority += 300 * (1 - usage) ** 3 + 60 * np.cos(cap * usage)
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.3) * 17 / p
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.018:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 8) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 9):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 70
            elif usage < 0.25:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1300) % (r + 5) in [0,2]:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 100
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 35
        prox = 0
        checks = [ (int(cap * 2700) % 21, 18), (int(cap * 850) % 25, -13), (int(cap * 190) % 11, 16) ]
        for val, adj in checks:
            if val == 0:
                prox += adj
            elif val == 4:
                prox -= adj // 2
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.015:
                prox += 22 / u
            elif diff < 0.04:
                prox += 14 / u
            else:
                prox -= 5 / u
        for v in range(1, 9):
            mod_val = int(cap * 1700) % (v + 10)
            if mod_val in [0, 5]:
                prox += v * 6
            elif mod_val == 4:
                prox -= v * 5
        for w in range(1, 6):
            mod_val2 = int(usage * 1700) % (w + 7)
            if mod_val2 in [0, 4]:
                prox += 12 * w
            elif mod_val2 == 5:
                prox -= 9 * w
        priority += prox
        if usage < 0.003:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2600) % 27 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 650) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
